"""sklearn.covariance — Covariance estimation."""
import numpy as np
from sklearn.base import BaseEstimator


class EmpiricalCovariance(BaseEstimator):
    """Maximum-likelihood covariance estimator.

    Parameters
    ----------
    assume_centered : bool, default=False
    """

    def __init__(self, assume_centered=False):
        self.assume_centered = assume_centered

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if self.assume_centered:
            self.location_ = np.zeros(X.shape[1])
        else:
            self.location_ = np.mean(X, axis=0)
        Xc = X - self.location_
        self.covariance_ = Xc.T @ Xc / X.shape[0]
        self.precision_ = np.linalg.pinv(self.covariance_)
        return self

    def score(self, X_test, y=None):
        X_test = np.asarray(X_test, dtype=float)
        return self.log_likelihood(X_test)

    def log_likelihood(self, X_test):
        Xc = X_test - self.location_
        n, p = Xc.shape
        sign, logdet = np.linalg.slogdet(self.covariance_)
        ll = -0.5 * (p * np.log(2 * np.pi) + logdet +
                      np.mean(np.sum(Xc @ self.precision_ * Xc, axis=1)))
        return ll


class LedoitWolf(EmpiricalCovariance):
    """Ledoit-Wolf shrinkage covariance estimator."""

    def __init__(self, assume_centered=False):
        self.assume_centered = assume_centered

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        n, p = X.shape
        if self.assume_centered:
            self.location_ = np.zeros(p)
        else:
            self.location_ = np.mean(X, axis=0)
        Xc = X - self.location_
        S = Xc.T @ Xc / n

        # Ledoit-Wolf optimal shrinkage
        X2 = Xc ** 2
        sample_sq = (X2.T @ X2) / n - S ** 2
        rho_num = np.sum(sample_sq)
        rho_denom = np.sum((S - np.diag(np.diag(S)) * (np.eye(p))) ** 2) + np.sum(np.diag(S) ** 2) - np.trace(S) ** 2 / p
        mu = np.trace(S) / p
        delta = np.sum((S - mu * np.eye(p)) ** 2) / p
        if delta == 0:
            self.shrinkage_ = 1.0
        else:
            beta = min(rho_num / (n * delta * p), 1.0)
            self.shrinkage_ = max(0.0, min(beta, 1.0))

        self.covariance_ = (1 - self.shrinkage_) * S + self.shrinkage_ * mu * np.eye(p)
        self.precision_ = np.linalg.pinv(self.covariance_)
        return self


class MinCovDet(EmpiricalCovariance):
    """Minimum Covariance Determinant (robust covariance).

    Simplified implementation using a subset-based approach.

    Parameters
    ----------
    support_fraction : float or None, default=None
    random_state : int or None, default=None
    """

    def __init__(self, support_fraction=None, random_state=None, assume_centered=False):
        self.support_fraction = support_fraction
        self.random_state = random_state
        self.assume_centered = assume_centered

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        n, p = X.shape
        rng = np.random.RandomState(self.random_state)
        h = int(np.ceil((n + p + 1) / 2.0)) if self.support_fraction is None \
            else int(np.ceil(self.support_fraction * n))
        h = max(h, p + 1)
        h = min(h, n)

        best_det = np.inf
        best_loc = None
        best_cov = None

        for _ in range(10):
            subset = rng.choice(n, size=h, replace=False)
            Xs = X[subset]
            loc = np.mean(Xs, axis=0) if not self.assume_centered else np.zeros(p)
            Xc = Xs - loc
            cov = Xc.T @ Xc / len(Xs)
            sign, logdet = np.linalg.slogdet(cov)
            det = logdet if sign > 0 else np.inf
            if det < best_det:
                best_det = det
                best_loc = loc
                best_cov = cov

        self.location_ = best_loc
        self.covariance_ = best_cov
        self.precision_ = np.linalg.pinv(self.covariance_)
        self.support_ = np.ones(n, dtype=bool)
        return self
